#include <iostream>
#include <cmath>
using namespace std;
long long n,e,d,p,q,k;
int main(){
    cin>>k;
    for(int i=1;i<=k;i++){
        cin>>n>>d>>e;
        long long delta=(n-e*d+2)*(n-e*d+2)-4*n;
        if(delta<0){
            cout<<"NO"<<endl;
            continue;
        }
        p=1.0*(n-e*d+2-sqrt(delta))/2;
        q=1.0*(n-e*d+2+sqrt(delta))/2;
        if(q*p==n && e*d==(p-1)*(q-1)+1 && q>0 && p>0)
            cout<<p<<' '<<q<<endl;
        else cout<<"NO"<<endl;
    }
    return 0;
}
